  // ---- Rezervasyon sayfasi: musaitlik arama ----
  search_section_title: { tr: "Uygun Evinizi Bulun", en: "Find Your Available Home", de: "Finden Sie Ihre verfügbare Wohnung", fr: "Trouvez votre logement disponible", ru: "Найдите доступное жильё", uk: "Знайдіть доступне помешкання", zh: "查找空房公寓" },
  search_section_sub: { tr: "Tarihlerinizi girin, o tarihlerde müsait olan evlerimizi görün.", en: "Enter your dates to see which of our homes are available.", de: "Geben Sie Ihre Daten ein, um zu sehen, welche unserer Wohnungen verfügbar sind.", fr: "Entrez vos dates pour voir quels logements sont disponibles.", ru: "Введите даты, чтобы увидеть, какое жильё доступно.", uk: "Введіть дати, щоб побачити, яке помешкання доступне.", zh: "输入您的日期，查看哪些公寓有空房。" },
