  search_checkout_label: { tr: "Çıkış Tarihi", en: "Check-out Date", de: "Abreisedatum", fr: "Date de départ", ru: "Дата выезда", uk: "Дата виїзду", zh: "退房日期" },
  search_dates_label: { tr: "Giriş - Çıkış Tarihleri", en: "Check-in - Check-out Dates", de: "An- und Abreisedatum", fr: "Dates d'arrivée et de départ", ru: "Даты заезда и выезда", uk: "Дати заїзду та виїзду", zh: "入住 - 退房日期" },
